import{_ as e,c as a,o as n,a1 as r}from"./chunks/framework.DDNAyvCW.js";const s="/assets/general.Dxab6Ale.png",m=JSON.parse('{"title":"General Settings","description":"","frontmatter":{},"headers":[],"relativePath":"docs/settings/general/index.md","filePath":"docs/settings/general/index.md"}'),d={name:"docs/settings/general/index.md"};function o(i,t,l,h,g,c){return n(),a("div",null,t[0]||(t[0]=[r('<h1 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h1><p>Customize Chaterm&#39;s appearance, language, layout, and editor behavior from General Settings.</p><p><img src="'+s+'" alt=""></p><h2 id="general-settings-1" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings-1" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Options</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Theme</strong></td><td>Dark, Light, Follow System</td><td>Follow System</td><td>Controls the interface color scheme. Dark reduces eye strain in low light; Light is best in bright environments.</td></tr><tr><td><strong>Background</strong></td><td>Enable / Disable</td><td>Disable</td><td>When enabled, you can upload a custom background image or select a system-provided one.</td></tr><tr><td><strong>Layout</strong></td><td>Terminal Layout, Agents Layout</td><td>Terminal Layout</td><td>Terminal Layout uses a traditional terminal-first view. Agents Layout prioritizes the AI panel.</td></tr><tr><td><strong>Language</strong></td><td>English, Simplified Chinese, Traditional Chinese, Deutsch, Francais, Italiano, Portugues, Russian, Japanese, Korean, Arabic</td><td>English</td><td>Sets the interface language. Changes take effect immediately without restarting.</td></tr><tr><td><strong>Watermark</strong></td><td>Enable / Disable</td><td>Disable</td><td>Displays a watermark overlay on the interface when enabled.</td></tr></tbody></table><h2 id="editor-settings" tabindex="-1">Editor Settings <a class="header-anchor" href="#editor-settings" aria-label="Permalink to &quot;Editor Settings&quot;">​</a></h2><p>These settings control the built-in code and text editor.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Options</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Font Size</strong></td><td>8 -- 32 px</td><td>14</td><td>Font size used in the editor.</td></tr><tr><td><strong>Line Height</strong></td><td>0 -- 48</td><td>0 (auto)</td><td>Spacing between lines. Set to 0 to let the editor calculate automatically.</td></tr><tr><td><strong>Font</strong></td><td>Preset monospace fonts</td><td>Cascadia Mono</td><td>Monospace font used in the editor.</td></tr><tr><td><strong>Tab Size</strong></td><td>1 -- 8 spaces</td><td>4</td><td>Number of spaces inserted when pressing Tab.</td></tr><tr><td><strong>Word Wrap</strong></td><td>Enable / Disable</td><td>Disable</td><td>When enabled, long lines wrap to fit the editor width instead of scrolling horizontally.</td></tr><tr><td><strong>Minimap</strong></td><td>Enable / Disable</td><td>Enable</td><td>Shows a small overview of the file on the right side of the editor.</td></tr><tr><td><strong>Mouse Wheel Zoom</strong></td><td>Enable / Disable</td><td>Disable</td><td>When enabled, use <code>Ctrl</code> + mouse wheel (or <code>Cmd</code> + mouse wheel on macOS) to zoom the editor font.</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/docs/settings/terminal/">Terminal Settings</a> -- configure terminal emulation, fonts, and cursor style</li><li><a href="/docs/settings/shortcuts/">Shortcut Settings</a> -- view and customize keyboard shortcuts</li></ul>',10)]))}const b=e(d,[["render",o]]);export{m as __pageData,b as default};
